import { Component, OnInit } from '@angular/core';
import { EditProfileService } from './edit-profile.service';
import { EditpubService } from './editpub.service';
import { Router } from '@angular/router';
@Component({
  selector: 'app-edit-pub',
  templateUrl: './edit-pub.component.html',
  styleUrls: ['./edit-pub.component.css',
  '../../../assets/cssfiles/bootstrap.css',
  '../../../assets/cssfiles/font-awesome.css',
  '../../../assets/chosen/chosen.css',
  '../../../assets/cssfiles/apps.css',
  '../../../assets/cssfiles/res.css',
  '../../../assets/cssfiles/apps_inner.css']
})
export class EditPubComponent implements OnInit {

  constructor(private epub:EditpubService,private edit:EditProfileService,private router:Router) { }
  userdata:any;
  p_name:any;
  p_email:any;
  p_phone:any;
  p_street:any;
  p_city:any;
  p_pin:any;
  p_state:any;
  p_country:any;
  file!:any;
  profile:any;
  fval:string='';
  ngOnInit(): void {
    this.epub.edit_profile(localStorage.getItem('pub-id')).subscribe(data=>{console.log(data);
    this.userdata=JSON.parse(data);
    this.p_name=this.userdata.message[0].name;
    this.p_email=this.userdata.message[0].email;
    this.p_phone=this.userdata.message[0].phone;
    this.p_street=this.userdata.message[0].street;
    this.p_city=this.userdata.message[0].city;
    this.p_state=this.userdata.message[0].state;
    this.p_country=this.userdata.message[0].country;
    this.p_pin=this.userdata.message[0].pincode;
    this.profile=this.userdata.message[0].profile_image;
    })
  }
 onChange(event:any){
  
    this.file = event.target.files[0];
    var ext = event.target.files[0].name.split('.').pop();
    console.log(ext);
    if (ext == "jpeg" || ext == "jpg" || ext=='png') {
      this.fval = event.target.files[0].name;
    }
    else {
      alert("Wrong Format!");
      this.fval = "";
 }
}
send_data(v1:any,v2:any,v3:any,v4:any,v5:any,v6:any,v7:any,v8:any){
  //console.log(v1+" "+v2+" "+v3+" "+v4+" "+v5+" "+v6+" "+v7+" "+v8+" "+this.file.name);
  this.edit.editprofile(localStorage.getItem('pub-id'),v1,v2,v3,v4,v5,v6,v7,v8,this.file).subscribe(data=>{console.log(data);
  var obj=JSON.parse(data);
  if(obj.success==1)
  { alert('Your profile has been updated successfully');
    // location.reload();
    this.router.navigate(['publisher/publisher-dashboard'])
  }
  else
  {alert('Error while updating.')}
  });
}
}
