import { Component, OnInit } from '@angular/core';
import { UserbookdetailspageComponent } from '../userbookdetailspage/userbookdetailspage.component';
import { UserbookshowService } from '../userbookshow.service';
import { Router } from '@angular/router'
@Component({
  selector: 'app-user-dashboard',
  templateUrl: './user-dashboard.component.html',
  styleUrls: ['./user-dashboard.component.css',
  '../../../assets/cssfiles/bootstrap.css',
  '../../../assets/cssfiles/font-awesome.css',
  '../../../assets/chosen/chosen.css',
  '../../../assets/cssfiles/apps.css',
  '../../../assets/cssfiles/res.css',
  '../../../assets/cssfiles/apps_inner.css']
})
export class UserDashboardComponent implements OnInit {

  constructor(private router:Router,private userbook:UserbookshowService, private bookpage:UserbookdetailspageComponent) { }
  bookdata:any;
  books:any=[];
  ngOnInit(): void {
    this.userbook.getbooks(localStorage.getItem('u-id'),localStorage.getItem('user-type_user'),localStorage.getItem('remember_token')).subscribe(data=>{console.log(data)
    this.bookdata=data;
    var obj=JSON.parse(this.bookdata);
    for(let i=0;i<obj.message.length;i++)
    {this.books[i]=obj.message[i];}
    console.log(this.bookdata); 
    })
  }
  showbook(v:any,v2:any){
    localStorage.setItem('user_book_id',v);
    localStorage.setItem('user_pub_id',v2);
    this.bookpage.ngOnInit();
    this.router.navigate(['/user/bookdetails']);
  }

}
