import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { CookieService } from 'ngx-cookie-service';
import { SubcatshowService } from 'src/app/subcatshow.service';
import { AuthService } from '../../auth.service';


@Component({
  selector: 'app-subcategory',
  templateUrl: './subcategory.component.html',
  styleUrls: ['./subcategory.component.css']
})
export class SubcategoryComponent implements OnInit {

  constructor(private router:Router,private cookieService:CookieService, private authserv:AuthService,private subshow:SubcatshowService) { }
  userData:any;
  category:any=[];
  ngOnInit(): void {
    this.subshow.show_sub().subscribe(data=>{console.log('Success!',data);
    this.userData=data;
    for(let i=0;i<this.userData.message.length;i++)
    {
       this.category[i]=this.userData.message[i].name;
       console.log(this.userData.message[i].name);
    }
  })
  }
  logout()
  {
    this.authserv.logout();
    this.cookieService.delete('cookie-name');
    this.router.navigate(['/admin/login']);
  }
}
