import { Component, OnInit } from '@angular/core';
import { ApprovebookService } from 'src/app/approvebook.service';
import { PublisherbookserviceService } from 'src/app/publisherbookservice.service';
import { RejectbookService } from 'src/app/rejectbook.service';
import { Router } from '@angular/router';
import { CookieService } from 'ngx-cookie-service';
import { AuthService } from '..//..//auth.service';

@Component({
  selector: 'app-publisherbooks',
  templateUrl: './publisherbooks.component.html',
  styleUrls: ['./publisherbooks.component.css']
})
export class PublisherbooksComponent implements OnInit {

  constructor(private router:Router,private cookieService:CookieService, private authserv:AuthService, private pubbookserve:PublisherbookserviceService,private appbook:ApprovebookService,private rejbook:RejectbookService) { }
  userdata:any;
  userdata1:any;
  totaldata:any=[];
  category:any=[];
  ngOnInit(): void {
    this.pubbookserve.getBooks().subscribe(data=>{console.log(data);
    this.userdata=data;
    for(let i=0;i<this.userdata.message.length;i++)
    {
      this.category[i]=this.userdata.message[i]
      //console.log(this.category[i]);
    }
    })
  }
  approval(v1:any,v2:any){
    console.log(v1+" "+v2);
    this.appbook.approvebooks(v1,v2).subscribe(data=>{console.log(data)
      this.userdata1=data;
      var obj =JSON.parse(this.userdata1);
       this.totaldata=obj.message;
       
      for(let i=0;i<this.totaldata.length;i++)
      {
        console.log(obj.message[i]);
        this.category[i]=this.totaldata[i];
        console.log(this.totaldata[i]);
        //console.log(this.category[i]);
      }
    })
    location.reload();
  }
  reject(v1:any,v2:any){
    console.log(v1+" "+v2);
    this.rejbook.rejectbooks(v1,v2).subscribe(data=>{console.log(data)
      this.userdata1=data;
      var obj =JSON.parse(this.userdata1);
       this.totaldata=obj.message;
      for(let i=0;i<this.totaldata.length;i++)
      {
        this.category[i]=this.totaldata[i];
        //console.log(this.category[i]);
      }})
      location.reload();
  }
  logout()
  {
    this.authserv.logout();
    this.cookieService.delete('cookie-name');
    this.router.navigate(['/admin/login']);
  }
}
