import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
//import { AnyNaptrRecord } from 'dns';
import { CookieService } from 'ngx-cookie-service';
import { CatserveService } from 'src/app/catserve.service';
import { PublishercategoryshowService } from 'src/app/publishercategoryshow.service';
import { PublishersubcategoryshowService } from 'src/app/publishersubcategoryshow.service';
import { SubcatshowService } from 'src/app/subcatshow.service';
import { CatShowService } from '../../dashboard/cat-show.service';
import { pubsubCat } from '..//../pubsubcat';
import { Book } from '..//..//book';
import { BookuploadService } from 'src/app/bookupload.service';
import { myobj } from '..//..//myobj';
import { SplitbookService } from './splitbook.service';

declare var showprofile: any;
declare var PreviewImage: any;
@Component({
  selector: 'app-ebookupload',
  templateUrl: './ebookupload.component.html',
  styleUrls: ['./ebookupload.component.css',
    '../../../assets/cssfiles/bootstrap.css',
    '../../../assets/cssfiles/font-awesome.css',
    '../../../assets/chosen/chosen.css',
    '../../../assets/cssfiles/apps.css',
    '../../../assets/cssfiles/res.css',
    '../../../assets/cssfiles/apps_inner.css'
  ]
})
export class EbookuploadComponent implements OnInit {

  fval: string = '';
  constructor(private split: SplitbookService, private router: Router, private cookieService: CookieService, private showcat: PublishercategoryshowService, private showsubcat: PublishersubcategoryshowService, private upld: BookuploadService) { }
  userData: any = [];
  category: any = [];
  userData1: any = [];
  category1: any = [];
  bookdata: any;
  bookdata1: any;
  endpage: any;
  pages: any;
  b: any;
  pgbar:number=0;
  pgbstring:string='';
  counter_temp: number = 0;
  counter: number = 0;
  b1 = new myobj('');
  progress_show:boolean=false;
  //b=new Book('',null,null,'','','','','','','','','','user');
  //b=new Book()
  pubcat = new pubsubCat('');
  k: string = '';
  opshow: boolean = false;
  file!: File;
  file_book!: any;
  t: string = '';
  buttonshow: boolean = false;
  id = '1';
  publisher_name = '';
  category_id = '';
  sub_category_id = '';
  book_name = '';
  author_name = '';
  price = '';
  isbn_no = '';
  about_book = '';
  about_author = '';
  book_image: any;
  book_pdf: any;
  user_name = 'user';
  m: any;
  m1: any;
  temp: any;
  formData = new FormData();
  formData1 = new FormData();
  ngOnInit(): void {
    this.showcat.getData().subscribe(data => {
      // console.log('Success!', data)
      this.userData = data;
      for (let i = 0; i < this.userData.message.length; i++) {
        this.category[i] = this.userData.message[i].name;
        //console.log(this.userData.message[i].name);
      }
    })
  }
  show(v: any) {
    if (v != 'default') {

      this.opshow = true;
      for (let i = 0; i < this.userData.message.length; i++) {
        if (v == this.userData.message[i].name) {
          this.pubcat.category_id = this.userData.message[i]._id;
          this.m1 = this.userData.message[i]._id;
        }
      }
      this.showsubcat.getData(this.pubcat).subscribe(data => {
        // console.log('Success!', data);
        this.userData1 = data;
        for (let i = 0; i < this.userData1.message.length; i++) {
          this.category1[i] = this.userData1.message[i].name;
          this.m = this.userData1.message[i]._id;
          //console.log(this.userData.message[i].name);
        }
      })
    }
    else {
      this.buttonshow = false;
      this.opshow = false;
      this.k = 'default';
      this.category1[0] = '';
    }
  }
  drag() {
    showprofile();
  }
  logout() {
    localStorage.removeItem('pub-token');
    localStorage.setItem('pub-loggedin', 'false');
    this.cookieService.delete('pub-cookie-name');
    this.router.navigate(['/publisher/logpub']);
  }
  onChange_book(event: any) {
    this.file_book = event.target.files[0];
    this.t = event.target.files[0].name;
    var ext = event.target.files[0].name.split('.').pop();
    if (ext == "pdf" || ext == "PDF") {
      this.t = event.target.files[0].name;
      this.buttonshow = true;
      PreviewImage();
    }
    else {
      alert("Wrong Format!");
      this.t = "";
    }
  }//
  preventNonNumericalInput(e: any) {
    e = e || window.event;
    var charCode = (typeof e.which == "undefined") ? e.keyCode : e.which;
    var charStr = String.fromCharCode(charCode);

    if (!charStr.match(/^[0-9]+$/))
      e.preventDefault();
  }
  preventNonCurrencyInput(e: any) {
    e = e || window.event;
    var charCode = (typeof e.which == "undefined") ? e.keyCode : e.which;
    var charStr = String.fromCharCode(charCode);

    if (!charStr.match(/^[0-9]+$/))
      e.preventDefault();
  }
  onChange(event: any) {
    this.file = event.target.files[0];
    var ext = event.target.files[0].name.split('.').pop();

    if (ext == "jpeg" || ext == "jpg"|| ext=='png') {
      this.fval = event.target.files[0].name;
    }
    else {
      alert("Wrong Format!");
      this.fval = "";
    }
  }
  showvalues(v1: any, v2: any, v3: any, v4: string, v5: any, v6: any, v7: any, v8: any, v9: any, v10: any, v11: any, v12: any, v13: any) {

    this.b = new Book(localStorage.getItem('pub-id'), this.file_book, v1, this.m1, this.m, v4, v5, v6, v7, this.file, v8, v9, localStorage.getItem('token'), v10, v11, v12, v13);
    this.b.book_pdf = this.file_book;
    this.b1.book_name = v4;
   
   
   this.progress_show=true;
    this.upld.upload(this.b).subscribe(data => {

      this.bookdata = JSON.parse(data);

      var checkpgcount = 100;
      if (this.bookdata.totalpage > checkpgcount) {
        for (this.pages = 1; this.pages <= this.bookdata.totalpage; this.pages++) {

          if (this.pages == checkpgcount) {
            var startpage = checkpgcount - 99;
            this.endpage = checkpgcount;
            console.log("start page" + startpage);
            console.log("end page" + this.endpage);
            checkpgcount += 100;
            this.counter_temp++;
            this.split.upload_book(this.bookdata.mainbook_url, this.bookdata.id, this.bookdata.book_id, this.bookdata.contents_from, this.bookdata.contents_to, this.bookdata.random_from, this.bookdata.random_to, this.bookdata.price, this.bookdata.user_name, this.bookdata.uploaded_page = this.pages, startpage, this.endpage).subscribe(data1 => {
              console.log(data1);
              this.temp = JSON.parse(data1);
              console.log(this.temp.success);
              if (this.temp.success == 1) {
                this.counter++;
                this.pgbar = ((this.counter / this.counter_temp) * 100);
                this.pgbstring=this.pgbar.toString();
                console.log(this.pgbstring);
                document.getElementById("myBar")?.style.width!=this.pgbar+"%";
                document.getElementById("myBar")?.innerHTML!=this.pgbar+"%"
                //document.getElementById("myBar")?.style.width!=this.counter+'%';
                console.log(this.pgbar);
                if (this.counter == this.counter_temp) {
                  this.router.navigate(['/publisher/book-list']);
                }
             }
            })
          } else if (this.pages == this.bookdata.totalpage) {
            var startpage = checkpgcount - 99;
            this.endpage = this.bookdata.totalpage;
            this.counter_temp++;

            console.log("start page" + startpage);
            console.log("end page" + this.endpage);
            this.split.upload_book(this.bookdata.mainbook_url, this.bookdata.id, this.bookdata.book_id, this.bookdata.contents_from, this.bookdata.contents_to, this.bookdata.random_from, this.bookdata.random_to, this.bookdata.price, this.bookdata.user_name, this.bookdata.uploaded_page = this.pages, startpage, this.endpage).subscribe(data1 => {
              console.log(data1);
              this.temp = JSON.parse(data1);
              if (this.temp.success == 1) {
                this.counter++;
                this.pgbar =((this.counter/this.counter_temp)*100);
                
                this.pgbstring=this.pgbar.toString();
                document.getElementById("myBar")?.style.width!=this.pgbar+"%";
                document.getElementById("myBar")?.innerHTML!=this.pgbar+"%";
                //document.getElementById("myBar")?.style.width!=this.counter+'%';
                console.log(this.pgbstring);
                console.log(this.pgbar);

                if (this.counter == this.counter_temp) {
                  this.router.navigate(['/publisher/book-list']);
                }
                // this.counter_temp.push(this.counter);
              }
            })
          }

        }
        // console.log(this.counter_temp);
      } else {
        var startpage = 1;
        this.endpage = this.bookdata.totalpage;
        console.log('single time');
        this.split.upload_book(this.bookdata.mainbook_url, this.bookdata.id, this.bookdata.book_id, this.bookdata.contents_from, this.bookdata.contents_to, this.bookdata.random_from, this.bookdata.random_to, this.bookdata.price, this.bookdata.user_name, this.bookdata.uploaded_page = this.pages, startpage, this.endpage).subscribe(data1 => {
          console.log(data1);
          this.temp = JSON.parse(data1);
          if (this.temp.success == 1) {
            this.router.navigate(['/publisher/book-list']);
          }
        })
      }

    })
  }
}


