import { Component, OnInit } from '@angular/core';
import {CatserveService} from '../../catserve.service'
import { ICat } from '../../cat';
import { Router } from '@angular/router';
import { AuthService } from '../../auth.service';
import { CookieService } from 'ngx-cookie-service';
@Component({
  selector: 'app-create-category',
  templateUrl: './create-category.component.html',
  styleUrls: ['./create-category.component.css']
})
export class CreateCategoryComponent implements OnInit {

  constructor(private cats:CatserveService,private router:Router,private authserv:AuthService, private cookieService:CookieService) { }
  nm=new ICat('');
  userData:any;
  ngOnInit(): void {
  }
  create_cat(v:string){
    this.nm.name=v;
   this.cats.getData(this.nm).subscribe(data=>{console.log('Success!',data);
    this.userData=data;
    console.log(this.userData.message.name);
    this.router.navigate(['/admin/category']);
  })
  //this.category.push(v);
  }
  logout(){
    this.authserv.logout();
    this.cookieService.delete('cookie-name');
    this.router.navigate(['/admin/login']);
  }
}
