import { AfterViewInit, Component, OnInit } from '@angular/core';
import { UsereditService } from '../useredit.service';
import { Router } from '@angular/router';
import { UsersidebarinfoService } from 'src/app/usersidebarinfo.service';
import { UserbookdetailsService } from '../userbookdetails.service';
import { UserdetailsService } from '../userdetails.service';
@Component({
  selector: 'app-edit-user',
  templateUrl: './edit-user.component.html',
  styleUrls: ['./edit-user.component.css',
  '../../../assets/cssfiles/bootstrap.css',
  '../../../assets/cssfiles/font-awesome.css',
  '../../../assets/chosen/chosen.css',
  '../../../assets/cssfiles/apps.css',
  '../../../assets/cssfiles/res.css',
  '../../../assets/cssfiles/apps_inner.css']
})
export class EditUserComponent implements AfterViewInit {

  constructor(private edit:UsereditService,private router:Router,private user:UserdetailsService) { }
  userdata:any;
  p_name:any;
  p_email:any;
  p_phone:any;
  p_street:any;
  p_city:any;
  p_pin:any;
  p_state:any;
  p_country:any;
  file!:any;
  profile:any;
  profile_image:any;
  fval:string='';
  ngAfterViewInit(): void {
    this.user.get_Details(localStorage.getItem('u-id'),localStorage.getItem('user-type_user'),localStorage.getItem('remember_token')).subscribe(data=>{console.log(data)
      var obj=JSON.parse(data);
      this.p_name=obj.message[0].name;
      this.p_email=obj.message[0].email;
      this.p_phone=obj.message[0].phone;
      this.p_street=obj.message[0].street;
      this.p_city=obj.message[0].city;
      this.p_country=obj.message[0].country;
      this.p_pin=obj.message[0].pincode;
      this.p_state=obj.message[0].state;
      this.profile=obj.message[0].image_url;
      this.profile_image=obj.message[0].profile_image;
      //localStorage.setItem('profile_image',this.profile_image);
    })
  }
  onChange(event:any){
  
    this.file = event.target.files[0];
    //localStorage.setItem('profile',this.file);
    var ext = event.target.files[0].name.split('.').pop();
    console.log(ext);
    if (ext == "jpeg" || ext == "jpg") {
      this.fval = event.target.files[0].name;
    }
    else {
      alert("Wrong Format!");
      this.fval = "";
 }
}
send_data(v1:any,v2:any,v3:any,v4:any,v5:any,v6:any,v7:any,v8:any){
  //console.log(v1+" "+v2+" "+v3+" "+v4+" "+v5+" "+v6+" "+v7+" "+v8+" "+this.file.name);
  this.edit.edit_profile(localStorage.getItem('u-id'),v1,v2,v3,v4,v5,v6,v7,v8,localStorage.getItem('user-type_user'),localStorage.getItem('remember_token'),this.file).subscribe(data=>{console.log(data);
  var obj=JSON.parse(data);
  if(obj.success==1)
  { alert('Your profile has been updated successfully');
    // location.reload();
    this.router.navigate(['user/user_dashboard'])
  }
  else
  {alert('Error while updating.')}
  });
 }
}
