import { Component, OnInit } from '@angular/core';
import { AllbooksComponent } from '../allbooks/allbooks.component';
import { AllbooksearchService } from '../allbooks/allbooksearch.service';
import { AutosearchService } from '../allbooks/autosearch.service';
import { Router } from '@angular/router';
@Component({
  selector: 'app-index-nav-header',
  templateUrl: './index-nav-header.component.html',
  styleUrls: ['./index-nav-header.component.css',
  '../../assets/cssfiles/bootstrap.css',
  '../../assets/cssfiles/font-awesome.css',
  '../../assets/chosen/chosen.css',
  '../../assets/cssfiles/apps.css',
  '../../assets/cssfiles/res.css',
  '../../assets/cssfiles/apps_inner.css']
})
export class IndexNavHeaderComponent implements OnInit {

  constructor(private router:Router,private bk:AutosearchService,private allbooksrc:AllbooksComponent) { }
  placeholder:string='Search by Name, Author, Publisher, ISBN';
  keyword='book_name';
  bookname:any;
  bookname1:any;
  obj:any;
  search_value:any;
  old_search_value:any;
  ngOnInit(): void {
    this.bk.getbook().subscribe(data=>{
      //console.log(data);
      this.obj=JSON.parse(data);
      this.bookname=this.obj.message;
      this.bookname1=this.obj.message;
      
    
    })
  }
  selectEvent(event:any){
    //console.log(event.book_name);
    console.log("event.book_name="+event.book_name);
    this.search_value=event.book_name;
    this.router.navigate(['/allbooks',this.search_value]);
    // this.router.navigate(['/allbooks']);
    this.allbooksrc.change_address(this.search_value)
  }
  onChangeSearch(event:any){
    //console.log(event);
    
    this.search_value=event;
    function checkKey(val:any) {
     return (val.book_name.toUpperCase()).includes(event.toUpperCase())||(val.isbn_no.toUpperCase()).includes(event.toUpperCase())||(val.author_name.toUpperCase()).includes(event.toUpperCase())||(val.publisher_name.toUpperCase()).includes(event.toUpperCase());
    }
    this.bookname=this.bookname1.filter(checkKey);
    //console.log(this.bookname);
    
  }
  onFocused(event:any){}
  show_result(){
    
    console.log("search value in show result "+this.search_value);
    this.router.navigate(['/allbooks',this.search_value]);
    this.allbooksrc.change_address(this.search_value)
    
}
}
