import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { CookieService } from 'ngx-cookie-service';
import { AuthService } from '../../auth.service';
import { DataService } from '../../data.service';
@Component({
  selector: 'app-users',
  templateUrl: './users.component.html',
  styleUrls: ['./users.component.css']
})
export class UsersComponent implements OnInit {
 
 

  constructor(private router:Router,private cookieService:CookieService,private authserv:AuthService,private data:DataService) { }
  userData:any=[];
  page:number=1;
  totalrecords:number=0;
  config:any;
  ngOnInit(): void {
    var id = localStorage.getItem('token1');
    var name=this.cookieService.get('cookie-name');
    if(name=='')
    this.router.navigate(['/login']);
      this.data.get_api().subscribe(data=>{
          this.userData=data;
      });
      this.config={
        itemsPerPage: 3,
        currentPage: 1,
        totalRecords: this.userData.length}
  }
  logout()
  {
    this.authserv.logout();
    this.cookieService.delete('cookie-name');
    this.router.navigate(['/admin/login']);
  }
 
  pageChanged(event:any){
    this.config.currentPage=event;
  }


}


